Toggle The Worst Puzzle Trap.command:
const {NONE} =  CONST.WALL_SENSE_TYPES;
const scene = fromUuidSync("Scene.k00aKaNPsITajfm8");
const toggleableWalls = scene.walls.filter(w => w.flags?.world?.toggleable);
toggleableWalls.forEach(w => {
  w.update({
  light: w.light === NONE ? w.flags.world.toggleable.light : NONE,
  sight: w.sight === NONE ? w.flags.world.toggleable.sight : NONE,
  sound: w.sound === NONE ? w.flags.world.toggleable.sound : NONE,
  move: w.move === NONE ? w.flags.world.toggleable.move : NONE
  });
});

const tiles = [
  fromUuidSync("Scene.k00aKaNPsITajfm8.Tile.mHKnmqqUSHCVhZhx"),
  fromUuidSync("Scene.k00aKaNPsITajfm8.Tile.uE1YLw8vgdG5x3J8")
];
tiles.forEach(p => p.update({ hidden: !p.hidden }));

